Parm(&EmpCod);

Event Start
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = Page.Rows
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'CREDUPNRO' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'CREDUPNRO' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'CREDUPNRO' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) &CreSts = nullvalue(&CreSts) &CreRecPag = nullvalue(&CreRecPag) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Duplicatas Descontadas'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = GridPaginationBar.RowsPerPageSelectedValue Grid.FirstPage()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
CreDupNro.Link = VerDUplicata.Link('MONITORADUPLICATASDESCONTADAS', EmpCod, FilCod, CreCod)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ActionGroupGrid.Clear() &ActionGroupGrid.AddItem(0, 'WWP_ActionGroupCaption') If (CreSts = Status_Duplicata.Descontada) &ActionGroupGrid.AddItem(1, 'Extornar') Endif If &ActionGroupGrid.Count = 1 &ActionGroupGrid.Class = !'Invisible' Else &ActionGroupGrid.Class = !'Attribute' EndIf
if CreNovCliRaz_Formula.Length() > 30 &CreNovCliRaz = substr(CreNovCliRaz_Formula, 1, 30) + '...' Else &CreNovCliRaz = CreNovCliRaz_Formula EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = True AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersIgnoreFirst = True Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False &DynamicFiltersIgnoreFirst = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector1.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'AddDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled3 = True AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled2 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector2.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'RemoveDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersRemoving = True &DynamicFiltersEnabled3 = False Do 'SaveDynFiltersState' Do 'ResetDynFilters' Do 'LoadDynFiltersState' &DynamicFiltersRemoving = False Grid.Refresh()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &DynamicFiltersSelector3.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event &ActionGroupGrid.Click
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case &ActionGroupGrid = 1 Do 'Do Extornar' EndCase &ActionGroupGrid = 0
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DVelop_ConfirmPanel_Extornar.Close
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If DVelop_ConfirmPanel_Extornar.Result = !'Yes' Do 'Do Action Extornar' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoSair'
wwDesconto.Call()
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event 'DoExport'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Generate Excel spreadsheet and download it. Do 'LoadGridState' ExportMonitoraDuplicatasDescontadas.Call(&ExcelFilename, &ErrorMessage) If (&ExcelFilename <> "") Link(&ExcelFilename) Else msg(&ErrorMessage) Endif
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro1.Visible = False &CreBloNro1.Visible = False TableMergedDynamicFiltersCreDtaVct1.Visible = False TableMergedDynamicFiltersCreDtaEms1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.Visible = True Case &DynamicFiltersSelector1 = !'CREBLONRO' &CreBloNro1.Visible = True Case &DynamicFiltersSelector1 = !'CREDTAVCT' TableMergedDynamicFiltersCreDtaVct1.Visible = True Case &DynamicFiltersSelector1 = !'CREDTAEMS' TableMergedDynamicFiltersCreDtaEms1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro2.Visible = False &CreBloNro2.Visible = False TableMergedDynamicFiltersCreDtaVct2.Visible = False TableMergedDynamicFiltersCreDtaEms2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.Visible = True Case &DynamicFiltersSelector2 = !'CREBLONRO' &CreBloNro2.Visible = True Case &DynamicFiltersSelector2 = !'CREDTAVCT' TableMergedDynamicFiltersCreDtaVct2.Visible = True Case &DynamicFiltersSelector2 = !'CREDTAEMS' TableMergedDynamicFiltersCreDtaEms2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreDupNro3.Visible = False &CreBloNro3.Visible = False TableMergedDynamicFiltersCreDtaVct3.Visible = False TableMergedDynamicFiltersCreDtaEms3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.Visible = True Case &DynamicFiltersSelector3 = !'CREBLONRO' &CreBloNro3.Visible = True Case &DynamicFiltersSelector3 = !'CREDTAVCT' TableMergedDynamicFiltersCreDtaVct3.Visible = True Case &DynamicFiltersSelector3 = !'CREDTAEMS' TableMergedDynamicFiltersCreDtaEms3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'Do Extornar'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&EmpCod_Selected = EmpCod &FilCod_Selected = FilCod &CreCod_Selected = CreCod DVelop_ConfirmPanel_Extornar.Confirm()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'Do Action Extornar'
&DesCod = 0 Do 'GetCodigoDesconto' if &DesCod <> 0 ExtornoDesconto.Call(&EmpCod_Selected , &FilCod_Selected, &CreCod_Selected,&DesCod) Refresh else msg('Duplicata sem desconto vinculado.') EndIf
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILTERFULLTEXT" &FilterFullText.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRDUP" &CreVlrDup.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CREBLONRO' &CreBloNro1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'CREDTAVCT' &CreDtaVct1.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To1.FromString(&GridStateDynamicFilter.ValueTo) Case &DynamicFiltersSelector1 = !'CREDTAEMS' &CreDtaEms1.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 0);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CREBLONRO' &CreBloNro2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'CREDTAVCT' &CreDtaVct2.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To2.FromString(&GridStateDynamicFilter.ValueTo) Case &DynamicFiltersSelector2 = !'CREDTAEMS' &CreDtaEms2.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 0);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CREBLONRO' &CreBloNro3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'CREDTAVCT' &CreDtaVct3.FromString(&GridStateDynamicFilter.Value) &CreDtaVct_To3.FromString(&GridStateDynamicFilter.ValueTo) Case &DynamicFiltersSelector3 = !'CREDTAEMS' &CreDtaEms3.FromString(&GridStateDynamicFilter.Value) &CreDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"FILTERFULLTEXT", "", not &FilterFullText.IsEmpty(), 0, &FilterFullText, '') WWP_GridStateAddFilterValue(&GridState, !"CREVLRDUP", "", not &CreVlrDup.IsEmpty(), 0, &CreVlrDup.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"CRESTS", "", not &CreSts.IsEmpty(), 0, &CreSts, '') WWP_GridStateAddFilterValue(&GridState, !"CRERECPAG", "", not &CreRecPag.IsEmpty(), 0, &CreRecPag, '') WWP_GridStateAddFilterValue(&GridState, !"CREVLRSDO", "", not &CreVlrSdo.IsEmpty(), 0, &CreVlrSdo.ToString().Trim(), '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' AND not &CreDupNro1.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro1.ToString() Case &DynamicFiltersSelector1 = !'CREBLONRO' AND not &CreBloNro1.IsEmpty() &GridStateDynamicFilter.Value = &CreBloNro1.ToString() Case &DynamicFiltersSelector1 = !'CREDTAVCT' AND not (&CreDtaVct1.IsEmpty() AND &CreDtaVct_To1.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaVct1.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaVct_To1.ToString() Case &DynamicFiltersSelector1 = !'CREDTAEMS' AND not (&CreDtaEms1.IsEmpty() AND &CreDtaEms_To1.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaEms1.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaEms_To1.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() OR not &GridStateDynamicFilter.ValueTo.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' AND not &CreDupNro2.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro2.ToString() Case &DynamicFiltersSelector2 = !'CREBLONRO' AND not &CreBloNro2.IsEmpty() &GridStateDynamicFilter.Value = &CreBloNro2.ToString() Case &DynamicFiltersSelector2 = !'CREDTAVCT' AND not (&CreDtaVct2.IsEmpty() AND &CreDtaVct_To2.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaVct2.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaVct_To2.ToString() Case &DynamicFiltersSelector2 = !'CREDTAEMS' AND not (&CreDtaEms2.IsEmpty() AND &CreDtaEms_To2.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaEms2.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaEms_To2.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() OR not &GridStateDynamicFilter.ValueTo.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' AND not &CreDupNro3.IsEmpty() &GridStateDynamicFilter.Value = &CreDupNro3.ToString() Case &DynamicFiltersSelector3 = !'CREBLONRO' AND not &CreBloNro3.IsEmpty() &GridStateDynamicFilter.Value = &CreBloNro3.ToString() Case &DynamicFiltersSelector3 = !'CREDTAVCT' AND not (&CreDtaVct3.IsEmpty() AND &CreDtaVct_To3.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaVct3.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaVct_To3.ToString() Case &DynamicFiltersSelector3 = !'CREDTAEMS' AND not (&CreDtaEms3.IsEmpty() AND &CreDtaEms_To3.IsEmpty()) &GridStateDynamicFilter.Value = &CreDtaEms3.ToString() &GridStateDynamicFilter.ValueTo = &CreDtaEms_To3.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() OR not &GridStateDynamicFilter.ValueTo.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Duplicatas"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'GetCodigoDesconto'
For each order EmpCod,DesCod,DesDupItmCod where EmpCod = &EmpCod where DesCreCod = &CreCod_Selected &DesCod = DesCod exit EndFor
EndSub
